## Overview
Create React Query hooks for fetching enriched clone data and bulk deletion.

## Implementation

### 1. Create useEnrichedClones Hook
**File:** `src/Homespun.Web/src/features/clones/hooks/use-enriched-clones.ts`

```typescript
import { useQuery } from "@tanstack/react-query"
import { getEnrichedClones } from "@/api"

export const enrichedClonesQueryKey = (projectId: string) => 
  ["clones", "enriched", projectId] as const

export function useEnrichedClones(projectId: string) {
  return useQuery({
    queryKey: enrichedClonesQueryKey(projectId),
    queryFn: () => getEnrichedClones({ query: { projectId } }),
    select: (response) => response.data,
  })
}
```

### 2. Create useBulkDeleteClones Hook
**File:** `src/Homespun.Web/src/features/clones/hooks/use-bulk-delete-clones.ts`

```typescript
import { useMutation, useQueryClient } from "@tanstack/react-query"
import { bulkDeleteClones } from "@/api"
import { enrichedClonesQueryKey } from "./use-enriched-clones"

export function useBulkDeleteClones() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: ({ projectId, clonePaths }: { 
      projectId: string
      clonePaths: string[] 
    }) => bulkDeleteClones({ 
      query: { projectId },
      body: { clonePaths } 
    }),
    onSuccess: (_, { projectId }) => {
      // Invalidate enriched clones query
      queryClient.invalidateQueries({ 
        queryKey: enrichedClonesQueryKey(projectId) 
      })
      // Also invalidate regular clones query used by branches tab
      queryClient.invalidateQueries({ 
        queryKey: ["clones", projectId] 
      })
    },
  })
}
```

### 3. Export Hooks
**File:** `src/Homespun.Web/src/features/clones/hooks/index.ts`

```typescript
