## Tool Schemas
\`\`\`typescript
WorkflowPassData: {
  description: "Store intermediate data in workflow context",
  input_schema: {
    type: "object",
    properties: {
      key: { type: "string", description: "Context key" },
      value: { description: "Data to store" },
      merge: { type: "boolean", description: "Merge with existing" }
    },
    required: ["key", "value"]
  }
